const now = new Date();
const etOffsetMs = -5 * 60 * 60 * 1000;
const nowEt = new Date(now.getTime() + etOffsetMs);

// End = today ET midnight; Start = end - 7 days
const endEt = new Date(nowEt);
endEt.setUTCHours(0, 0, 0, 0);
const startEt = new Date(endEt);
startEt.setUTCDate(endEt.getUTCDate() - 7);

// Prior-week comparison range
const priorEndEt = new Date(startEt);
const priorStartEt = new Date(priorEndEt);
priorStartEt.setUTCDate(priorEndEt.getUTCDate() - 7);

const toUtc = d => new Date(d.getTime() - etOffsetMs).toISOString();

return [{ json: {
  start_utc: toUtc(startEt),
  end_utc: toUtc(endEt),
  prior_start_utc: toUtc(priorStartEt),
  prior_end_utc: toUtc(priorEndEt),
  week_start_date: startEt.toISOString().slice(0, 10),
  week_end_date: endEt.toISOString().slice(0, 10),
  generated_at: now.toISOString()
}}];

const range = $node['Compute Last 7 Days Range'].json;
const metrics = $node['List Metrics Last 7d'].all().map(i => i.json.fields || i.json);
const priorMetrics = $node['List Metrics Prior 7d'].all().map(i => i.json.fields || i.json);
const orders = $node['List Orders Last 7d'].all().map(i => i.json.fields || i.json);
const content = $node['List Content Last 7d'].all().map(i => i.json.fields || i.json);

const sumMetric = (rows, name) => rows.filter(r => r['Metric name'] === name).reduce((a, r) => a + (Number(r['Value']) || 0), 0);
const avgMetric = (rows, name) => {
  const vals = rows.filter(r => r['Metric name'] === name).map(r => Number(r['Value']) || 0);
  return vals.length ? vals.reduce((a, b) => a + b, 0) / vals.length : 0;
};

const revenue_week = sumMetric(metrics, 'revenue_total');
const revenue_prior = sumMetric(priorMetrics, 'revenue_total');
const wow_revenue_pct = revenue_prior ? ((revenue_week - revenue_prior) / revenue_prior) * 100 : 0;

const orders_week = sumMetric(metrics, 'orders_total');
const orders_prior = sumMetric(priorMetrics, 'orders_total');
const wow_orders_pct = orders_prior ? ((orders_week - orders_prior) / orders_prior) * 100 : 0;

// Channel revenue
const channels = {
  is: sumMetric(metrics, 'revenue_is'),
  etsy: sumMetric(metrics, 'revenue_etsy'),
  gumroad: sumMetric(metrics, 'revenue_gumroad')
};

// Top products from Orders
const productMap = {};
for (const o of orders) {
  const sku = Array.isArray(o['Product']) ? (o['Product'][0]?.name || o['Product'][0] || 'unknown') : (o['Product'] || 'unknown');
  const key = String(sku);
  if (!productMap[key]) productMap[key] = { sku: key, units: 0, revenue: 0 };
  productMap[key].units += 1;
  productMap[key].revenue += Number(o['Gross amount']) || 0;
}
const top_products = Object.values(productMap).sort((a, b) => b.revenue - a.revenue).slice(0, 5);

// Refund + behaviour rates (latest available)
const latest = (name) => {
  const rows = metrics.filter(r => r['Metric name'] === name);
  if (!rows.length) return 0;
  const sorted = rows.sort((a, b) => new Date(b['Date']) - new Date(a['Date']));
  return Number(sorted[0]['Value']) || 0;
};
const refund_rate_rolling_30 = latest('refund_rate_rolling_30');
const orderbump_rate = avgMetric(metrics, 'orderbump_rate');
const oto_rate = avgMetric(metrics, 'oto_rate');

// Anomaly flags
const anomalies = [];
if (refund_rate_rolling_30 > 0.08) anomalies.push({ metric: 'refund_rate_rolling_30', value: refund_rate_rolling_30, target: '<0.08' });
if (orderbump_rate < 0.15 && orders_week > 0) anomalies.push({ metric: 'orderbump_rate', value: orderbump_rate, target: '>0.15' });

const content_summary = {
  total_published: content.length,
  by_type: content.reduce((acc, c) => { const t = c['Type'] || 'unknown'; acc[t] = (acc[t] || 0) + 1; return acc; }, {}),
  total_views: content.reduce((a, c) => a + (Number(c['Views']) || 0), 0),
  total_conversions: content.reduce((a, c) => a + (Number(c['Conversions']) || 0), 0)
};

const blob = {
  week_start: range.week_start_date,
  week_end: range.week_end_date,
  revenue_week: Number(revenue_week.toFixed(2)),
  revenue_prior_week: Number(revenue_prior.toFixed(2)),
  wow_revenue_pct: Number(wow_revenue_pct.toFixed(2)),
  orders_week,
  orders_prior_week: orders_prior,
  wow_orders_pct: Number(wow_orders_pct.toFixed(2)),
  channel_revenue: channels,
  top_products,
  orderbump_rate: Number(orderbump_rate.toFixed(4)),
  oto_rate: Number(oto_rate.toFixed(4)),
  refund_rate_rolling_30: Number(refund_rate_rolling_30.toFixed(4)),
  content_summary,
  anomalies
};

return [{ json: { blob, blob_json: JSON.stringify(blob, null, 2), range } }];

