const resp = $input.first().json;
const blobItem = $node['Assemble Weekly Blob'].first().json;

// Anthropic response shape: { content: [{ type: 'text', text: '...' }] }
let markdown = '';
if (resp && Array.isArray(resp.content)) {
  markdown = resp.content.filter(c => c.type === 'text').map(c => c.text).join('\n').trim();
} else if (resp && typeof resp.completion === 'string') {
  markdown = resp.completion.trim();
} else {
  throw new Error('Unexpected Claude response shape: ' + JSON.stringify(resp).slice(0, 300));
}

if (!markdown) throw new Error('Empty briefing returned by Claude');

const subject = `STR Ledger Weekly Briefing — ${blobItem.range.week_start_date} → ${blobItem.range.week_end_date}`;

return [{ json: {
  subject,
  markdown,
  week_start: blobItem.range.week_start_date,
  week_end: blobItem.range.week_end_date,
  blob: blobItem.blob,
  generated_at: new Date().toISOString()
}}];

const input = $input.first().json;
return [{ json: {
  timestamp: new Date().toISOString(),
  workflow: 'W10-weekly-ops-briefing',
  node: $node.name || 'unknown',
  error_message: input.error?.message || JSON.stringify(input).slice(0, 500),
  payload: JSON.stringify(input).slice(0, 500),
  status: 'Open'
}}];
